#include <string.h>
#include <stdio.h>

void format_values(char *buf, size_t sz) {
    int n = 42;
    float f = 3.14159f;
    char *s = "clings";
    unsigned int h = 0xDEAD;
    snprintf(buf, sz, "Int     : %d\nFloat   : %.2f\nString  : %s\nHex     : 0x%04X\nPadded  : %08d\nNeg pad : %-10d|\n",
             n, f, s, h, n, n);
}

int main(void) {
    {
        char buf[128];
        format_values(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "Int     : 42")) ? 1 : 0);
    }
    {
        char buf[128];
        format_values(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "Float   : 3.14")) ? 1 : 0);
    }
    {
        char buf[128];
        format_values(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "String  : clings")) ? 1 : 0);
    }
    {
        char buf[128];
        format_values(buf, sizeof(buf));
        printf("%d\n", (strstr(buf, "Hex     : 0xDEAD")) ? 1 : 0);
    }
    return 0;
}

